// Build a readable weekly report from the three Plausible calls.
// Works with Plausible Cloud and self-hosted; Umami needs minor field tweaks (see README).
const cfg = $('Config').item.json;
const agg = ($('Totals').item.json.results) || {};
const pages = ($('Top pages').item.json.results) || [];
const sources = ($('Top sources').item.json.results) || [];

const num = (x) => (x && x.value != null ? x.value : 0);
const visitors = num(agg.visitors);
const pageviews = num(agg.pageviews);
const bounce = num(agg.bounce_rate);
const durSec = num(agg.visit_duration);
const dur = `${Math.floor(durSec / 60)}m ${Math.round(durSec % 60)}s`;

const pagesHtml = pages.map((p) => `<tr><td>${p.page}</td><td class="r">${p.visitors}</td></tr>`).join('') || '<tr><td colspan="2">Sin datos</td></tr>';
const sourcesHtml = sources.map((s) => `<tr><td>${s.source}</td><td class="r">${s.visitors}</td></tr>`).join('') || '<tr><td colspan="2">Sin datos</td></tr>';

const html = `<!doctype html><html><head><meta charset="utf-8"><style>
  body { font-family: -apple-system, Segoe UI, Roboto, Arial, sans-serif; color:#1a1a2e; }
  h2 { margin:0 0 2px; }
  .muted { color:#6b7280; }
  .cards { display:flex; gap:12px; margin:18px 0; }
  .card { background:#f8fafc; border:1px solid #e5e7eb; border-radius:8px; padding:12px 16px; flex:1; }
  .card .n { font-size:22px; font-weight:700; }
  table { width:100%; border-collapse:collapse; margin:6px 0 18px; }
  th,td { padding:7px 9px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; }
  th { background:#1a1a2e; color:#fff; font-size:11px; text-transform:uppercase; }
  td.r,th.r { text-align:right; }
</style></head><body>
  <h2>Informe semanal · ${cfg.site_id}</h2>
  <div class="muted">Periodo: últimos ${cfg.period}</div>
  <div class="cards">
    <div class="card"><div class="muted">Visitantes</div><div class="n">${visitors}</div></div>
    <div class="card"><div class="muted">Páginas vistas</div><div class="n">${pageviews}</div></div>
    <div class="card"><div class="muted">Rebote</div><div class="n">${bounce}%</div></div>
    <div class="card"><div class="muted">Duración media</div><div class="n">${dur}</div></div>
  </div>
  <h3>Páginas más vistas</h3>
  <table><thead><tr><th>Página</th><th class="r">Visitantes</th></tr></thead><tbody>${pagesHtml}</tbody></table>
  <h3>Fuentes de tráfico</h3>
  <table><thead><tr><th>Fuente</th><th class="r">Visitantes</th></tr></thead><tbody>${sourcesHtml}</tbody></table>
  <div class="muted" style="font-size:11px">Generado con n8n + Plausible.</div>
</body></html>`;

return [{ json: { report_to: cfg.report_to, site_id: cfg.site_id, html } }];
